const emailId = $json.body.emailId;
if (!emailId) return [{ json: { error: 'No emailId provided' } }];

// Apply 'TR' category to email via Microsoft Graph API
// The Outlook credential gives us an access token
const response = await this.helpers.httpRequest({
  method: 'PATCH',
  url: `https://graph.microsoft.com/v1.0/me/messages/${emailId}`,
  headers: {
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    categories: ['TR']
  }),
  authentication: 'predefinedCredentialType',
  nodeCredentialType: 'microsoftOutlookOAuth2Api'
});

return [{ json: { success: true, emailId } }];
